patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index b6a80fef4217..249b73406a15 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -561,12 +561,10 @@ bool llvm::isValidAssumeForContext(const Instruction *Inv,
   return false;
 }

-// TODO: cmpExcludesZero misses many cases where `RHS` is non-constant but
-// we still have enough information about `RHS` to conclude non-zero. For
-// example Pred=EQ, RHS=isKnownNonZero. cmpExcludesZero is called in loops
-// so the extra compile time may not be worth it, but possibly a second API
-// should be created for use outside of loops.
-static bool cmpExcludesZero(CmpInst::Predicate Pred, const Value *RHS) {
+// cmpExcludesZero supports non-constant RHS via isKnownNonZero check when
+// SimplifyQuery is available.
+static bool cmpExcludesZero(CmpInst::Predicate Pred, const Value *RHS,
+                            const SimplifyQuery *Q = nullptr) {
   // v u> y implies v != 0.
   if (Pred == ICmpInst::ICMP_UGT)
     return true;
@@ -583,6 +581,11 @@ static bool cmpExcludesZero(CmpInst::Predicate Pred, const Value *RHS) {
     return !TrueValues.contains(Zero);
   }

+  // For non-constant RHS, we can still conclude V != 0 if RHS is known non-zero
+  // and Pred is EQ.
+  if (Pred == ICmpInst::ICMP_EQ && Q && isKnownNonZero(RHS, *Q))
+    return true;
+
   auto *VC = dyn_cast<ConstantDataVector>(RHS);
   if (VC == nullptr)
     return false;
@@ -672,7 +675,7 @@ static bool isKnownNonZeroFromAssume(const Value *V, const SimplifyQuery &Q) {
     if (!match(I->getArgOperand(0), m_c_ICmp(Pred, m_V, m_Value(RHS))))
       continue;

-    if (cmpExcludesZero(Pred, RHS) && isValidAssumeForContext(I, Q.CxtI, Q.DT))
+    if (cmpExcludesZero(Pred, RHS, &Q) && isValidAssumeForContext(I, Q.CxtI, Q.DT))
       return true;
   }

@@ -2746,9 +2749,9 @@ static bool isKnownNonNullFromDominatingCondition(const Value *V,
       continue;

     bool NonNullIfTrue;
-    if (cmpExcludesZero(Pred, RHS))
+    if (cmpExcludesZero(Pred, RHS, nullptr))
       NonNullIfTrue = true;
-    else if (cmpExcludesZero(CmpInst::getInversePredicate(Pred), RHS))
+    else if (cmpExcludesZero(CmpInst::getInversePredicate(Pred), RHS, nullptr))
       NonNullIfTrue = false;
     else
       continue;
@@ -3179,7 +3182,7 @@ static bool isKnownNonZeroFromOperator(const Operator *I,
       if (!IsTrueArm)
         Pred = ICmpInst::getInversePredicate(Pred);

-      return cmpExcludesZero(Pred, X);
+      return cmpExcludesZero(Pred, X, &Q);
     };

     if (SelectArmIsNonZero(/* IsTrueArm */ true) &&
@@ -3211,7 +3214,7 @@ static bool isKnownNonZeroFromOperator(const Operator *I,
           // If we're using the false successor, invert the predicate.
           if (FalseSucc == PN->getParent())
             Pred = CmpInst::getInversePredicate(Pred);
-          if (cmpExcludesZero(Pred, X))
+          if (cmpExcludesZero(Pred, X, &Q))
             return true;
         }
       }

